const AddCustomer = () => {
  const { selectedBank, setCurrentPage, mobile } = useBankTransfer();
  const today = new Date();
  const eighteenYearsAgo = new Date(
    today.getFullYear() - 18,
    today.getMonth(),
    today.getDate()
  )
    .toISOString()
    .split("T")[0];
  const hundredYearsAgo = new Date(
    today.getFullYear() - 100,
    today.getMonth(),
    today.getDate()
  )
    .toISOString()
    .split("T")[0];
  const [formData, setFormData] = useState({
    firstName: "",
    lastName: "",
    customerMobile: mobile,
    dob: "",
    country: "India",
    pinCode: "",
    state: "",
    city: "",
    district: "",
    area: "",
    aadharNumber: "",
  });

  const validationSchema = Yup.object({
    firstName: Yup.string().required("First Name is required"),
    lastName: Yup.string().required("Last Name is required"),
    customerMobile: Yup.string()
      .matches(/^[6-9]\d{9}$/, "Enter a valid 10-digit mobile number")
      .required("Mobile number is required"),
    dob: Yup.string().required("Date of Birth is required"),
    pinCode: Yup.string()
      .matches(/^\d{6}$/, "Pincode must be 6 digits")
      .required("Pincode is required"),
    state: Yup.string().required("State is required"),
    city: Yup.string().required("City is required"),
    district: Yup.string().required("District is required"),
    area: Yup.string().required("Area is required"),
    aadharNumber: Yup.string()
      .matches(/^\d{12}$/, "Aadhaar must be 12 digits")
      .required("Aadhaar number is required"),
  });

  const handleSubmit = async (values) => {
    setFormData(values);

    let body = {
      user_id: window.localStorage.getItem("userIdToken"),
      customer_mobile: mobile,
      name: values.firstName,
      dob: values.dob,
      country: values.country,
      city: values.city,
      state: values.state,
      pincode: values.pinCode,
      district: values.district,
      area: values.area,
      api_id: selectedBank,
      lastName: values.lastName,
      adhaar_number: values.aadharNumber,
    };
    try {
      const res = await createCustomer(body);
      if (res?.data?.statusCode == "200") {
        setCurrentPage("otp-page");
      }

      if (res?.data?.statusCode === "008") {
        setCurrentPage("otp-page");
      }

      toastMessage(res?.data?.error, res?.data?.message);
    } catch (error) {}
  };

  const fetchPincode = async (value, setFieldValue, setErrors) => {
    try {
      if (!value) {
        setErrors({ pincode: "Pincode is required" });
        return;
      } else if (!/^[0-9]{6}$/.test(value)) {
        setErrors({ pincode: "Pincode must be exactly 6 digits" });
        return;
      }

      setErrors({ pincode: "" });

      const res = await getDetailByPin(value);

      if (res?.data?.error) {
        setErrors({ pincode: "Invalid Pincode or not found" });
      } else {
        setFieldValue("city", res.data?.data?.city || "");
        setFieldValue("state", res.data?.data?.state || "");
        setFieldValue("district", res.data?.data?.district || "");
        setFieldValue("area", res.data?.data?.sub_distance || "");
      }
    } catch (error) {
      console.error("Error fetching pincode details:", error);
      setErrors({ pincode: "Something went wrong. Please try again." });
    }
  };

  return (
    <CustomBox>
      <Box display="flex" alignItems="center" gap={2}>
        <IconButton sx={{ color: NAVY_TEXT }} onClick={() => setCurrentPage("money-transfer")}>
          <ArrowBackIosNewIcon />
        </IconButton>
        <Typography sx={{ color: NAVY_TEXT, fontFamily: FONT_DISPLAY }} fontWeight="bold" fontSize={18}>
          Add New Customer
        </Typography>
      </Box>

      <Box maxWidth="1000px" m="auto">
        <Formik
          initialValues={formData}
          validationSchema={validationSchema}
          onSubmit={async (values, { setSubmitting }) => {
            await handleSubmit(values);
            setSubmitting(false);
          }}
          enableReinitialize
        >
          {({ errors, touched, setErrors, setFieldValue, isSubmitting }) => (
            <Form>
              <Box p={3}>
                <Grid container rowSpacing={6} columnSpacing={6}>
                  <Grid item xs={12} sm={6}>
                    <Field
                      name="firstName"
                      as={CustomTextFieldAddCustomer}
                      label="First Name *"
                      fullWidth
                      error={touched.firstName && Boolean(errors.firstName)}
                      helperText={touched.firstName && errors.firstName}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Field
                      name="lastName"
                      as={CustomTextFieldAddCustomer}
                      label="Last Name *"
                      fullWidth
                      error={touched.lastName && Boolean(errors.lastName)}
                      helperText={touched.lastName && errors.lastName}
                    />
                  </Grid>

                  <Grid item xs={12} sm={6}>
                    <Field
                      name="customerMobile"
                      as={CustomTextFieldAddCustomer}
                      label="Customer Mobile *"
                      fullWidth
                      disabled
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Field
                      name="dob"
                      as={CustomTextFieldAddCustomer}
                      label="Date Of Birth *"
                      fullWidth
                      type="date"
                      InputLabelProps={{ shrink: true }}
                      error={touched.dob && Boolean(errors.dob)}
                      helperText={touched.dob && errors.dob}
                      inputProps={{
                        max: eighteenYearsAgo,
                        min: hundredYearsAgo,
                      }}
                    />
                  </Grid>

                  <Grid item xs={12} sm={6}>
                    <Field
                      name="country"
                      as={CustomTextFieldAddCustomer}
                      label="Country *"
                      fullWidth
                      disabled
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Field
                      name="pinCode"
                      as={CustomTextFieldAddCustomer}
                      label="Pin Code *"
                      onChange={(e) => {
                        const value = e.target.value.replace(/\D/g, "").slice(0, 6);
                        setFieldValue("pinCode", value);

                        if (value.length === 6) {
                          fetchPincode(value, setFieldValue, setErrors);
                        }
                      }}
                      fullWidth
                      error={touched.pinCode && Boolean(errors.pinCode)}
                      helperText={touched.pinCode && errors.pinCode}
                    />
                  </Grid>

                  <Grid item xs={12} sm={6}>
                    <Field
                      name="state"
                      as={CustomTextFieldAddCustomer}
                      label="State *"
                      fullWidth
                      error={touched.state && Boolean(errors.state)}
                      helperText={touched.state && errors.state}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Field
                      name="city"
                      as={CustomTextFieldAddCustomer}
                      label="City *"
                      fullWidth
                      error={touched.city && Boolean(errors.city)}
                      helperText={touched.city && errors.city}
                    />
                  </Grid>

                  <Grid item xs={12} sm={6}>
                    <Field
                      name="district"
                      as={CustomTextFieldAddCustomer}
                      label="District *"
                      fullWidth
                      error={touched.district && Boolean(errors.district)}
                      helperText={touched.district && errors.district}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <Field
                      name="area"
                      as={CustomTextFieldAddCustomer}
                      label="Area *"
                      fullWidth
                      error={touched.area && Boolean(errors.area)}
                      helperText={touched.area && errors.area}
                    />
                  </Grid>

                  <Grid item xs={12} sm={6}>
                    <Field
                      name="aadharNumber"
                      as={CustomTextFieldAddCustomer}
                      label="Aadhaar Number *"
                      fullWidth
                      error={touched.aadharNumber && Boolean(errors.aadharNumber)}
                      helperText={touched.aadharNumber && errors.aadharNumber}
                    />
                  </Grid>

                  <Grid item xs={12}>
                    <Button
                      type="submit"
                      variant="contained"
                      sx={gradientBtnSx(isSubmitting)}
                      disabled={isSubmitting}
                    >
                      Submit
                    </Button>
                  </Grid>
                </Grid>
              </Box>
            </Form>
          )}
        </Formik>
      </Box>
    </CustomBox>
  );
};

