const KYCPage = () => {
  const devices = [
    { id: "2", img: imgg2, name: "Mantra" },
    { id: "3", img: imgg3, name: "Mantra L1" },
    { id: "4", img: imgg4, name: "Morpho" },
  ];
  const { walletCall, wadhValue, selectedBank, mobile, setCurrentPage } = useBankTransfer();
  const [selectedDeviceId, setSelectedDeviceId] = useState(null);

  const { loading, captureFingerprint } = useFingerprintCapture({ wadhValue });

  const handleDeviceSelect = (id) => {
    setSelectedDeviceId(id);
  };

  const selectedDevice = devices.find((d) => d.id === selectedDeviceId);

  const handleCaptureFingerprint = withLocation(async (latitude, longitude) => {
    if (!selectedDevice) return alert("Please select a device.");

    try {
      const result = await captureFingerprint(selectedDevice.name);
      const xmlStr = result.pidData + "<bookz/>";
      const encodedXml = window.btoa(
        new XMLSerializer().serializeToString(
          new DOMParser().parseFromString(xmlStr, "application/xml")
        )
      );

      const body = {
        customer_mobile: mobile,
        latitude,
        longitude,
        biometric_data: encodedXml,
        api_id: selectedBank,
      };

      const res = await dmtkycapi(body);
      if (res?.data?.statusCode === "200" && !res?.data?.error) {
        setCurrentPage("send-money-page");
        walletCall();
      }
      toastMessage(res?.data?.error, res?.data?.message);
    } catch (error) {
      alert("Capture failed: " + error.message);
    }
  });

  return (
    <>
      <CustomBox>
        <Box display="flex" alignItems="center" gap={2} mb={2}>
          <IconButton sx={{ color: NAVY_TEXT }} onClick={() => setCurrentPage("money-transfer")}>
            <ArrowBackIosNewIcon />
          </IconButton>
          <Typography sx={{ color: NAVY_TEXT, fontFamily: FONT_DISPLAY }} fontWeight="bold" fontSize={18}>
            Verify KYC
          </Typography>
        </Box>

        <Grid container spacing={2} sx={{ p: 2 }}>
          <Grid item xs={12}>
            <Grid container spacing={2}>
              {devices?.map((device, index) => (
                <Grid item xs={6} sm={4} md={2} key={index}>
                  <Card
                    onClick={() => handleDeviceSelect(device.id)}
                    sx={{
                      display: "flex",
                      flexDirection: "column",
                      alignItems: "center",
                      p: 1,
                      height: "100%",
                      border: selectedDeviceId === device.id ? `1.5px solid ${PRIMARY}` : `1px solid ${LINE}`,
                      backgroundColor: selectedDeviceId === device.id ? "rgba(185,138,70,0.08)" : "#FFFFFF",
                      borderRadius: 2,
                      boxShadow: 0,
                      cursor: "pointer",
                      transition: "all 0.2s ease",
                    }}
                  >
                    <CardMedia
                      component="img"
                      image={device.img}
                      alt={device.name}
                      sx={{ height: 80, objectFit: "contain", mb: 1 }}
                    />
                    <CardContent sx={{ p: 0 }}>
                      <Typography variant="body2" align="center" sx={{ fontWeight: 500, fontFamily: FONT_DISPLAY, color: NAVY_TEXT }}>
                        {device.name}
                      </Typography>
                    </CardContent>
                  </Card>
                </Grid>
              ))}
            </Grid>
          </Grid>

          <Grid item xs={12} textAlign="center">
            <Button
              variant="contained"
              disabled={!selectedDeviceId || loading}
              onClick={handleCaptureFingerprint}
              sx={{ mt: 3, ...gradientBtnSx(!selectedDeviceId || loading) }}
            >
              {loading ? "Capturing..." : "Capture Fingerprint"}
            </Button>
          </Grid>
        </Grid>
      </CustomBox>
    </>
  );
};

